#!/usr/bin/env bash
# noip-noi.sh — 备战 NOIP/NOI 冲刺 SOP walkthrough for 青少年编程教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年编程教育"
WORKFLOW="备战 NOIP/NOI 冲刺"

usage() {
  cat <<EOF
noip-noi.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./noip-noi.sh             # interactive
  ./noip-noi.sh --dry-run
  ./noip-noi.sh --json
  ./noip-noi.sh --explain
  ./noip-noi.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "备战 NOIP/NOI 冲刺" 工作流。

一句话: 在赛前3-6个月进入冲刺阶段，停止新知学习，集中强化真题训练、模拟赛、心理调适，最大化竞赛发挥。

入门 SOP 共 6 步, 失败模式自检 0 项。

相关心智模型:
  • 制作即学习 (Making Is Learning): 编程教育的核心不是教「编程语言语法」, 而是让学生通过创造可分享的外部作品来建构内部知识 — Papert 的建构主义 (constructionism) 是整个领域的哲学根基
  • 低地板、高天花板、宽墙壁 (Low Floor, High Ceiling, Wide Walls): 好的编程教育工具必须同时满足三个维度 — 入门门槛低 (low floor, 6 岁能开始)、能力上限高 (high ceiling, 能做复杂项目)、创作方向广 (wide walls, 不限于一种

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "现状诊断与能力摸底: 用3-5套历年真题（CSP-J近3年/NOIP近5年）计时完成，统计每题AC率和时间分布；识别高频失分知识点和\"会但不稳\"的知识点；inputs: 历年真题，outputs: 能力摸底报告。"
  "制定冲刺优先级: 将知识点分为3类——A类（稳定可拿分，保持熟练度）/ B类（会但不稳，重点强化）/ C类（从未掌握，赛前放弃，避免分散精力）；inputs: 摸底报告，outputs: 知识点优先级矩阵。"
  "规划每周训练节奏: 每周安排：3次专项练习（各1-2小时）+ 1次全真模拟赛（完整时长+真实评测环境）+ 1次错题复盘；参考 USACO Guide 的冲刺节奏建议 (evidence: [T03-S006])；inputs: 优先级矩阵，outputs: 周训练日历。"
  "全真模拟赛演练: 每次模拟赛严格执行考试规则（全程断网、限时、不查资料），赛后立即复盘——\"如果不卡在X，能多拿Y分\"；inputs: 训练日历，outputs: 模拟赛成绩记录+复盘日志。"
  "读题与策略训练: 训练\"5分钟读完4题并判断难易顺序\"，培养先做确定分、后攻部分分的答题策略；inputs: 真题集，outputs: 读题速度基准数据。"
  "赛前2周调整与心理准备: 停止新题训练，只做已会题型的\"热身练习\"；调整作息到与考试时间吻合；教师/家长进行考前谈话（正常发挥 > 超常发挥）；inputs: 冲刺训练完成，outputs: 考前状态评估+考试注意事项清单。"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "noip-noi-walkthrough"
fi
